namespace sv_5fee4feab5504c7dbdc66a080bab0795.Services;

public sealed class WarehouseStateService
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId => _currentWarehouseId;

    public IReadOnlyList<Warehouse> Warehouses { get; } =
    [
        new("WH-001", "Warehouse A — Main Distribution"),
        new("WH-002", "Warehouse B — East Regional"),
        new("WH-003", "Warehouse C — West Coast"),
    ];

    public event Func<Task>? OnWarehouseChanged;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;

        if (OnWarehouseChanged is not null)
            await OnWarehouseChanged.Invoke();
    }
}

public sealed record Warehouse(string Id, string Name);

namespace sv_5fee4feab5504c7dbdc66a080bab0795.Services;

public sealed class InventoryAlertService
{
    private static readonly Random _rng = new();
    private int _lastLowStockCount;

    public int LastLowStockCount => _lastLowStockCount;

    /// <summary>Raised after new alert data is fetched. All subscribers should re-render.</summary>
    public event Func<Task>? OnAlertCountChanged;

    /// <summary>Simulates a database query returning items below minimum stock levels.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate IO latency + random result
        return Task.FromResult(_rng.Next(0, 16));
    }

    /// <summary>
    /// Fetches new alert data for the given warehouse and notifies all subscribers.
    /// Called by the polling component so every consumer updates simultaneously.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        _lastLowStockCount = await GetLowStockCountAsync(warehouseId);

        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }
}

