@using sv_5fee4feab5504c7dbdc66a080bab0795.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<p>
    Currently viewing:
    <strong>@(WarehouseState.Warehouses.FirstOrDefault(w => w.Id == WarehouseState.CurrentWarehouseId)?.Name ?? WarehouseState.CurrentWarehouseId)</strong>
</p>

<div class="card mt-3" style="max-width:400px">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text display-4 @(AlertService.LastLowStockCount > 0 ? "text-danger" : "text-success")">
            @AlertService.LastLowStockCount
        </p>
        <p class="text-muted">items below minimum level (refreshes every 10 s)</p>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnWarehouseChanged += HandleWarehouseChanged;
        AlertService.OnAlertCountChanged += HandleAlertChanged;

        // Initial fetch + start polling
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        StartPolling();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            while (await timer.WaitForNextTickAsync(token))
            {
                await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
            }
        }, token);
    }

    private async Task HandleWarehouseChanged()
    {
        // Warehouse changed — refresh immediately and restart the polling cycle
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        StartPolling();
        await InvokeAsync(StateHasChanged);
    }

    private async Task HandleAlertChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        WarehouseState.OnWarehouseChanged -= HandleWarehouseChanged;
        AlertService.OnAlertCountChanged -= HandleAlertChanged;
    }
}

